const { neon } = require('@neondatabase/serverless');
const sql = neon(process.env.KEY);

const updates = [
  { id: 174, full_description: `<p>Belleza Fine Art occupies one of Old Bisbee's most atmospheric spaces in the historic Brewery Gulch district, where the former copper mining town's bohemian identity runs deepest. The gallery presents original paintings, fine art photography, and mixed-media work by regional artists who draw on the dramatic Sonoran Desert landscape, border culture, and the distinctive energy of life in a southern Arizona art town. Exhibitions rotate regularly, offering something new for return visitors alongside a consistent focus on work with genuine emotional depth and craft. The beautifully restored historic building adds architectural texture that commercial gallery spaces rarely achieve.</p>` },
  { id: 175, full_description: `<p>The Bisbee Arts &amp; Social Club functions as the beating heart of the town's creative community, bringing together working artists, curious visitors, and longtime locals in a space that blurs the line between gallery, meeting hall, and living room. Rotating exhibitions showcase the diverse talent that has made Bisbee one of Arizona's most compelling small art towns, alongside a calendar packed with artist talks, live music, open studio nights, and community events. The Social Club embodies the collaborative, anti-pretentious spirit that draws artists to Bisbee in the first place — a place where art is made and lived, not merely displayed.</p>` },
  { id: 177, full_description: `<p>The Copper Queen Hotel, built in 1902 at the height of Bisbee's copper mining prosperity, is one of the great historic hotels of the American Southwest — and its intimate gallery space carries the same layered atmosphere. Works on display engage directly with the themes that define Bisbee's character: the boom-and-bust drama of its mining heritage, the raw beauty of the Sonoran Desert, and the complex cultural life of the US-Mexico borderlands. An ideal introduction to the region's art scene for hotel guests, and a worthwhile stop for any gallery-goer exploring Old Bisbee's steep, storied streets.</p>` },
  { id: 176, full_description: `<p>Founded in 1994, Gallery Bisbee holds the distinction of being one of the longest-continuously-operating fine art galleries in Old Bisbee — a testament to the enduring artistic vitality of a town that has attracted painters, sculptors, and photographers for decades. The program balances established Southwestern artists with emerging voices from the border region, resulting in exhibitions that feel both rooted in tradition and genuinely alive to what's new. Work on view typically includes paintings, drawing, and sculpture made in direct response to the landscape and cultural life of southern Arizona and northern Mexico.</p>` },
  { id: 190, full_description: `<p>Set within the legendary Buffalo Chip Saloon complex, this gallery captures the spirit of Cave Creek's fiercely Western identity with a collection that leans into the mythology and reality of frontier life. Visitors will find an impressive assortment of Western American bronzes — from small-scale studies to monumental works — alongside oil paintings that celebrate the open range, desert wildlife, and the enduring culture of the cowboy. Artifacts and historical pieces add depth and context, making this as much a destination for Western history enthusiasts as for art collectors. It's the kind of gallery that could only exist in Cave Creek.</p>` },
  { id: 188, full_description: `<p>Serving the communities of Cave Creek and Carefree since 1972, the Desert Foothills Art Center has built more than five decades of programming dedicated to the art and heritage of the Sonoran Desert region. Gallery exhibitions rotate throughout the year, featuring local and regional artists working in watercolor, oil, ceramics, and sculpture, with a curatorial focus on work that reflects the landscape and culture of the northern Sonoran Desert. The center also maintains an active education calendar — classes, workshops, and youth programs — that connects the broader community to the creative life of northern Arizona's foothills communities.</p>` },
  { id: 189, full_description: `<p>Horton Gallery has established itself as one of the standout destinations in Cave Creek's lively arts community, known for a program that honors the Western American fine art tradition with both rigor and range. Bronze sculpture is a particular strength — the gallery represents artists working in the realist tradition, producing works that capture the movement of horses, the texture of desert rock, and the quiet dignity of wildlife in exacting detail. Oil paintings run from atmospheric plein air landscapes to more finished studio work celebrating the rugged terrain of Arizona and the broader American West. Highly recommended for collectors of traditional Western art.</p>` },
  { id: 115, full_description: `<p>Founded in 1993 and named for the vast Colorado Plateau country that surrounds Flagstaff, the Coconino Center for the Arts has grown into one of northern Arizona's most important nonprofit arts institutions. The center hosts a busy calendar of rotating exhibitions that span contemporary and traditional work, with particular attention to artists whose practice is rooted in the landscapes, Indigenous traditions, and multicultural character of the Colorado Plateau region. Beyond the gallery, Coconino is known for its role in Flagstaff's annual Festival of Science and the Viola Awards — a celebration of Arizona's creative community. Events and programming run year-round.</p>` },
  { id: 193, full_description: `<p>Established in 1966, the Flagstaff Arts Council is one of the oldest arts advocacy organizations in Arizona, and its gallery and programming remain central to the city's creative life. The council presents rotating gallery exhibitions featuring local and regional artists in a welcoming downtown location, while its advocacy work — supporting arts education, public art, and cultural programming across Coconino County — gives it an outsized impact on the region's creative ecosystem. For visitors new to Flagstaff's art scene, the Arts Council offers an excellent entry point, with staff who can point you toward studios, exhibitions, and artists throughout northern Arizona.</p>` },
  { id: 114, full_description: `<p>Founded in 1928, the Museum of Northern Arizona is one of the most significant natural and cultural history museums in the American West, and its art collections are extraordinary. The museum holds one of the world's finest assemblages of Hopi, Navajo, Zuni, and Pai pottery, weaving, jewelry, kachina carvings, and fine art — a collection built over a century of sustained engagement with the Indigenous communities of the Colorado Plateau. Annual Heritage Festivals celebrating Hopi, Navajo, Zuni, and Pai culture draw artists, scholars, and collectors from across the country. Set on a beautiful pine-forested campus at the base of the San Francisco Peaks, it is essential visiting for any serious student of Southwest art.</p>` },
  { id: 191, full_description: `<p>The Northern Arizona University Art Museum has maintained an active exhibition and collection program since 1970, occupying an important position within the university community and the broader Flagstaff arts scene. The permanent collection includes particular strengths in photography and regional Southwest art, with holdings that document the visual culture of the Colorado Plateau and Indigenous traditions of the Four Corners region. Temporary exhibitions present contemporary and modern work by artists of regional and national significance, often accompanied by lectures, artist talks, and educational programming tied to NAU's art department curriculum. Admission is typically free, making it one of the most accessible cultural venues in northern Arizona.</p>` },
  { id: 192, full_description: `<p>The Artists Gallery operates as a member-owned cooperative in the heart of downtown Flagstaff, with each artist participating in the running of the space and taking turns staffing the gallery — which means visitors often get to meet the people who made the work on the walls. The member roster is eclectic and accomplished, including painters working in the plein air tradition inspired by the ponderosa pine forests and high desert mesas surrounding Flagstaff, ceramic artists whose work reflects Indigenous pottery traditions, jewelers working in silver and stone, and photographers capturing the extraordinary light of northern Arizona. A genuine community gallery in the best sense.</p>` },
  { id: 172, full_description: `<p>Perched dramatically on Cleopatra Hill above the Verde Valley, Jerome is one of Arizona's most extraordinary art communities — a former copper mining boomtown that reinvented itself as an artist colony beginning in the 1970s. The Jerome Art Walk, held on the first Saturday evening of each month, is the best way to experience this remarkable concentration of working artists in a single evening. Galleries, studios, and artist-run spaces open their doors, often welcoming visitors with wine and conversation alongside whatever is on the walls. It's an uncommonly intimate experience — the artists are typically present, and the town's steep streets and Victorian architecture make the walk itself a pleasure.</p>` },
  { id: 170, full_description: `<p>Established in 2000, the Jerome Artists' Cooperative Gallery is a cornerstone of Jerome's art community — a collectively run space representing more than 40 artists who live and work in and around this historic hillside town. The range of work is deliberately broad: oil and acrylic paintings drawing on the Verde Valley's dramatic topography, hand-built and wheel-thrown ceramics, silver and turquoise jewelry made in the Southwest tradition, and sculpture in bronze, wood, and mixed media. Because member artists staff the gallery themselves, visitors frequently find themselves in direct conversation with the maker of the work they're examining — one of the great pleasures of a cooperative gallery model.</p>` },
  { id: 173, full_description: `<p>Priceless Pieces Fine Art brings a traditional fine art sensibility to Jerome's eclectic gallery scene, presenting paintings, sculpture, and photography that celebrate the dramatic natural landscapes of the Verde Valley and the broader Southwest. The gallery occupies historic Jerome architecture that adds considerable character to the viewing experience — thick stone walls, worn wood floors, and windows framing sweeping views of the valley below. Work on view tends toward the representational, with an emphasis on pieces that convey genuine emotional connection to place: the particular quality of Arizona light, the geological drama of canyon country, and the living culture of the desert Southwest.</p>` },
  { id: 171, full_description: `<p>Raku Gallery has been a fixture on Jerome's gallery trail since 1998, drawing visitors with a specialty in raku and studio ceramics that sets it apart from the painting-focused galleries lining the town's steep main street. Raku firing — a Japanese-derived technique that creates unpredictable, flame-kissed surface effects — produces work of extraordinary beauty and individuality, and the gallery presents it alongside paintings, mixed media works, and jewelry that share a similar commitment to process and material truth. Founded by artists who chose Jerome for its combination of community, landscape, and studio space, Raku Gallery embodies the spirit of the town's creative colony at its best.</p>` },
  { id: 187, full_description: `<p>Galeria Mesa is Mesa's flagship municipal gallery, a free public space in the heart of downtown presenting rotating exhibitions that span local, regional, and national contemporary art. The program deliberately serves a broad audience — from Mesa's tight-knit Latino arts community to national artists whose work speaks to the Southwest's cultural diversity — and the result is one of the Valley's most genuinely inclusive exhibition spaces. Admission is free and the gallery maintains extended hours, making it accessible to working families and students as well as dedicated collectors. Recent exhibitions have covered painting, photography, installation, and works on paper, with a consistent emphasis on art that engages thoughtfully with community and identity.</p>` },
  { id: 185, full_description: `<p>When Mesa Arts Center opened in 2005, it instantly became the largest arts complex in the American Southwest — five theaters and four gallery spaces set on a stunning campus of desert-inspired architecture. The visual arts program presents national and regional exhibitions of significant scope, with recent seasons bringing major contemporary artists to galleries that were purpose-built for ambitious installation and large-format work. Mesa Arts Center also functions as a community hub, with art education programs, public events, and an outdoor plaza that becomes a gathering point for the East Valley arts scene. The building alone — designed by Allied Works Architecture — is worth a visit.</p>` },
  { id: 186, full_description: `<p>Housed within the Mesa Arts Center campus, MCA Mesa presents dynamic temporary exhibitions with a curatorial focus on the diversity and vitality of contemporary art, particularly work rooted in or responsive to the American Southwest. The museum's program actively engages with the cultural complexity of the Phoenix metro area, bringing exhibitions that reflect the region's Latino heritage, Indigenous traditions, and rapidly evolving contemporary identity. Free admission for Mesa residents and low-cost tickets for all visitors make MCA Mesa one of the most accessible contemporary art venues in Arizona. The annual student exhibition consistently surfaces emerging local talent worth watching.</p>` },
  { id: 126, full_description: `<p>The Arizona Latino Arts and Cultural Center — known as ALAC — operates from the heart of Phoenix's Roosevelt Row Arts District with a mission to present and preserve the visual arts, culture, and heritage of Latino communities across Arizona and the broader Southwest. Gallery exhibitions have spanned muralism, photography, painting, printmaking, and installation art by Latino artists from Arizona, the US, Mexico, and Latin America. ALAC also commissions public murals and maintains an active calendar of cultural events, artist residencies, and educational programs tied to the community it serves. Essential for anyone seeking to understand the full cultural breadth of Phoenix's contemporary art scene.</p>` },
  { id: 37, full_description: `<p>The Phoenix location of Bentley Gallery occupies the Camelback Corridor — one of the city's most concentrated zones of design and art commerce — and brings a sophisticated contemporary program to match its setting. The gallery represents nationally recognized artists working in painting, sculpture, and photography, maintaining an exhibition calendar that moves fluidly between solo presentations and group shows designed to reveal unexpected connections between artists and ideas. Like the Scottsdale flagship, Bentley Gallery Phoenix is known for rigorous selection and a willingness to commit to artists over the long term, building bodies of work rather than chasing trends. An important destination for serious contemporary art collectors in the Valley.</p>` },
  { id: 39, full_description: `<p>The Cattle Track Artists Residency occupies a historic compound near the Scottsdale-Phoenix border that has quietly sustained a creative community for decades, offering working studio space to emerging and established artists in a setting deliberately removed from the commercial gallery circuit. The compound includes multiple studio buildings, outdoor work areas, and spaces for collaborative projects, and residents have included painters, sculptors, printmakers, and artists working across media. Periodic open studio events give the public a rare chance to see work in progress and meet the artists who have chosen this model of creative life — affordable space, community, and proximity to Phoenix's expanding arts infrastructure.</p>` },
  { id: 125, full_description: `<p>The George Washington Carver Museum and Cultural Center stands as the primary institution in Phoenix dedicated to preserving and celebrating the history, culture, and artistic contributions of the city's African American community. Founded in 1994 in the historically Black neighborhood of South Phoenix, the museum holds archives, artifacts, and artworks documenting over a century of African American life in Arizona — from the territorial era through the present day. The gallery program presents exhibitions of visual art alongside rotating displays from the permanent historical collection, and the center hosts community events, educational programs, and annual celebrations that connect new generations to South Phoenix's rich cultural heritage.</p>` },
  { id: 34, full_description: `<p>Founded in 1929 by Dwight and Maie Heard, the Heard Museum is recognized worldwide as the foremost institution dedicated to the art and culture of Native peoples of the American Southwest. The permanent collection is extraordinary in scope — Hopi kachina dolls, Navajo textiles and silverwork, pottery from San Ildefonso Pueblo, contemporary paintings and sculpture by Indigenous artists from across the region — and the temporary exhibition program brings major national and international presentations to Phoenix each season. The Annual Indian Fair &amp; Market, held each spring, is one of the most important Native American art markets in the country. Essential visiting for anyone serious about Southwest art and culture.</p>` },
  { id: 194, full_description: `<p>The Icehouse has been a cornerstone of Phoenix's Roosevelt Row Arts District since the neighborhood's emergence as the city's primary center for contemporary art, occupying a sprawling historic industrial building that gives ambitious installations, large-format paintings, and experimental work room to breathe. Monthly First Friday events draw hundreds of visitors to the building's multiple gallery spaces, often coinciding with opening receptions that run late into the evening. The programming skews adventurous — the Icehouse consistently presents work that challenges and provokes — while remaining genuinely accessible to new audiences drawn in by the energy of First Fridays on Roosevelt Row.</p>` },
  { id: 36, full_description: `<p>Modified Arts has been one of Roosevelt Row's most essential and uncompromising creative spaces since the neighborhood's early days as Phoenix's arts district, operating as a genuinely multi-use venue where experimental contemporary art, live music, and performance share equal billing. The space is raw and unpretentious — high ceilings, exposed concrete, minimal framing — which suits the work it tends to show: boundary-testing painting, installation, video, and performance art that wouldn't fit comfortably in a more formal gallery setting. Modified Arts has nurtured generations of Phoenix artists who needed a place to take risks and build community, and it continues to serve that function for the city's emerging creative generation.</p>` },
  { id: 38, full_description: `<p>Perihelion Arts is one of the most community-rooted galleries on Roosevelt Row, operating as an artist-run space with a genuine commitment to the emerging talent that makes Phoenix's creative scene feel alive and self-renewing. Exhibitions rotate regularly and showcase Arizona-based artists working across painting, drawing, photography, installation, and new media, with particular support for artists at early stages of their careers who need exhibition opportunities and critical engagement. Perihelion maintains an intentionally informal atmosphere — openings feel like gatherings of friends rather than commercial events — which reflects the cooperative values of the artists who run and exhibit in the space. Essential for visitors who want to see where Phoenix contemporary art is heading.</p>` },
  { id: 33, full_description: `<p>The Phoenix Art Museum is the largest art museum in the American Southwest, with a permanent collection of more than 19,000 works spanning American, Western American, Asian, Latin American, European, and fashion art across dozens of galleries. Founded in 1959, the museum has particular strengths in American Western painting, photography, and an exceptional fashion design collection that draws visitors from around the world. The Thorne Miniature Rooms — a series of extraordinarily detailed miniature period interiors — are a beloved and singular attraction. The temporary exhibition program regularly brings blockbuster presentations of international significance to Phoenix, making the museum central to the city's cultural calendar year-round.</p>` },
  { id: 127, full_description: `<p>Located in the heart of Midtown Phoenix, the Phoenix Center for the Arts offers a full complement of studio classes, workshops, and gallery programming across ceramics, painting, drawing, printmaking, fiber arts, and jewelry making, serving artists of all experience levels from complete beginners to working professionals. The center's gallery presents rotating exhibitions featuring both student work and invited artists whose practice connects to the center's studio disciplines, creating an environment where making and showing happen in close proximity. Community access is central to the mission — sliding scale tuition, extended hours, and a welcoming atmosphere make it a genuine arts hub for Midtown Phoenix residents and artists across the Valley.</p>` },
  { id: 128, full_description: `<p>S'edav Va'aki — a name in the O'odham language meaning "place of the dugout" — preserves one of the most significant archaeological sites in the American Southwest: a large pre-Columbian Hohokam community that thrived here between roughly 700 and 1400 CE. At the center of the site stands a massive earthen platform mound, one of the largest of its kind in North America, which formed the ceremonial and administrative heart of an ancient city that may have housed thousands of people. The museum's galleries present Hohokam pottery, shell jewelry, stone tools, and interpretive materials that bring this vanished civilization into focus for contemporary visitors — a rare and profound encounter with Arizona's deep human history.</p>` },
  { id: 196, full_description: `<p>Unexpected Gallery lives up to its name by consistently presenting work that defies easy categorization — a curated program built around Arizona-based artists whose work has attracted national collector attention without sacrificing the formal ambition and conceptual depth that makes it worth collecting. The gallery specializes in painting, sculpture, and works on paper, favoring artists whose practice has strong material intelligence alongside whatever conceptual or emotional narrative animates it. Located in downtown Phoenix, Unexpected Gallery occupies the space between the commercial energy of the gallery district and the more experimental spirit of artist-run spaces nearby, navigating it with considerable skill and curatorial confidence.</p>` },
  { id: 35, full_description: `<p>The Phoenix outpost of Wilde Meyer Gallery brings the celebrated Scottsdale gallery's signature commitment to vibrant, colorful contemporary Southwestern art to the Camelback Corridor, one of Phoenix's most design-conscious commercial districts. The program mirrors the Scottsdale flagship in its emphasis on artists who work in a distinctly Southwestern register — bold palettes, strong compositional energy, and a genuine relationship to the landscapes, light, and cultural life of the desert Southwest. Exhibitions rotate regularly and feature artists whose work has been widely collected throughout the Valley and beyond. An excellent entry point for collectors new to the contemporary Southwest art scene.</p>` },
  { id: 195, full_description: `<p>monOrchid is one of the most versatile and architecturally distinctive spaces in Phoenix's Roosevelt Row Arts District, occupying a beautifully renovated mid-century building that has been thoughtfully adapted to support gallery programming and larger cultural events. Rotating art exhibitions occupy the gallery spaces throughout the year, typically featuring contemporary artists whose work engages with the urban and cultural life of Phoenix and the broader Southwest. The space also hosts film screenings, musical performances, design events, and community activations that make it a genuine hub for the creative community rather than a gallery in the conventional sense. A reliable first stop for visitors wanting to understand the energy of Roosevelt Row.</p>` },
  { id: 179, full_description: `<p>Founded in 1954, the Mountain Artists Guild Gallery is one of the oldest continuously operating artist cooperatives in Arizona — a fact that gives it a sense of institutional depth that newer galleries inevitably lack. More than 100 member artists contribute work to rotating displays spanning oil and watercolor painting, photography, ceramics, jewelry, textile art, and sculpture across a range of styles from traditional to contemporary. The gallery sits steps from the iconic Prescott Courthouse Plaza, making it a natural anchor for visitors exploring downtown Prescott's shops and restaurants. With original work at a wide range of price points, it's particularly well suited to visitors looking to bring home something made by hand in Arizona.</p>` },
  { id: 178, full_description: `<p>The Phippen Museum of Western Art honors the legacy of George Phippen — a founding president of the Cowboy Artists of America and one of the defining painters of mid-20th century Western American art — while maintaining a living program dedicated to the ongoing tradition he helped establish. Permanent galleries present Phippen's own bronzes and paintings alongside artists he influenced, while rotating exhibitions bring contemporary Western painters and sculptors to Prescott throughout the year. The annual Phippen Museum Western Art Show &amp; Sale, held each Memorial Day weekend, is one of the most respected Western art markets in the country. Essential for collectors and enthusiasts of the American Western fine art tradition.</p>` },
  { id: 181, full_description: `<p>The Prescott Fine Arts Association has been the creative and social heart of Prescott's arts community since its founding in 1967, operating from a renovated historic church that gives its gallery and performance spaces an architectural character found nowhere else in the city. The gallery program presents rotating exhibitions of paintings, photography, and mixed-media work by regional artists, complemented by an active performing arts calendar that has made the PFAA one of the most important community theater organizations in northern Arizona. Art education programs for children and adults run year-round, and the association's central downtown location makes it a natural gathering place for Prescott's broad and engaged creative community.</p>` },
  { id: 180, full_description: `<p>Established in 1935 in a distinctive Pueblo Revival building that has become a landmark of Prescott's historic downtown, the Smoki Museum preserves and interprets the art, material culture, and ceremonial heritage of Native American peoples of the Southwest through collections spanning more than a century of acquisition and scholarship. The museum's holdings include significant assemblages of pottery, basketry, weaving, kachina dolls, jewelry, and ceremonial objects representing dozens of Southwestern tribal traditions, with particular strength in Hopi, Navajo, and Apache material culture. Interpretive programming connects these objects to the living cultures that produced them, situating the collection within an ongoing story of Indigenous artistic tradition rather than a static historical record.</p>` },
  { id: 6, full_description: `<p>Bentley Gallery has been one of the defining presences on the Scottsdale contemporary art scene since its founding in 1990, building a reputation for representing artists of genuine national and international significance alongside a commitment to long-term artist relationships that allows collectors to follow careers over time. The program spans painting, sculpture, and mixed-media work, with a curatorial sensibility that favors formal rigor and conceptual clarity over trend-chasing. Located in Old Town Scottsdale, the gallery is an anchor of the city's Thursday evening art walk and one of the stops serious collectors make on any extended visit to the Valley's gallery circuit. Opening receptions and artist talks are well attended and worth planning around.</p>` },
  { id: 14, full_description: `<p>The Cattle Track Arts Compound is one of the most historically significant creative communities in the American Southwest, a cluster of studios and living spaces that has housed working artists since the 1930s — long before Scottsdale's gallery district emerged around it. The compound's buildings have sheltered generations of painters, sculptors, printmakers, and ceramicists who valued affordable studio space, community, and proximity to the Sonoran Desert landscape. Today Cattle Track continues to operate as a working artists' community, with residents whose practices range from traditional Western painting to contemporary sculpture. Occasional open studio events give visitors a rare look behind the walls of one of Arizona's most storied creative compounds.</p>` },
  { id: 11, full_description: `<p>The Cosanti Foundation preserves and continues the visionary work of Italian-born architect Paolo Soleri (1919–2013), who settled in the Sonoran Desert and spent six decades creating a body of work that blurred the line between architecture, urban planning, and sculpture. The Cosanti studio complex in Scottsdale — hand-built by Soleri and his apprentices over many years — functions as both a working foundry and gallery, where the distinctive bronze and ceramic windbells synonymous with Soleri's aesthetic are still cast on site. Architectural drawings, scale models of his unrealized urban concepts, and documentation of Arcosanti — his experimental city under construction north of Phoenix since 1970 — round out a visit unlike any other in Arizona.</p>` },
  { id: 1, full_description: `<p>Exposures International Gallery of Fine Art is one of the largest privately owned art galleries in the world — a fact that becomes apparent the moment you enter the sprawling Old Town Scottsdale space, where room after room reveals painting, sculpture, and fine art photography by artists with international reputations and serious collector followings. Founded in 1980 and expanded many times over the decades, Exposures represents artists from across the United States, Europe, and beyond, with an emphasis on work that combines strong technical mastery with broad visual appeal. The gallery's scale means there is genuinely something for every taste and budget, from intimate works on paper to major sculptures. One of Scottsdale's defining gallery experiences.</p>` },
  { id: 12, full_description: `<p>Eye Lounge operates as an artist-run cooperative committed to supporting experimental and boundary-pushing contemporary work by Arizona-based artists — a mission that sets it apart from the commercially oriented galleries that dominate much of the Scottsdale scene. The cooperative structure means that decisions about programming and community events are made collectively by the artists themselves, resulting in a program that feels genuinely driven by the creative community rather than market considerations. Exhibitions rotate frequently and tend toward work that challenges conventional gallery norms — installation, performance documentation, video, and experimental painting all have a home at Eye Lounge. Essential for visitors who want to see where Arizona contemporary art is heading.</p>` },
  { id: 13, full_description: `<p>John C. Tanner Fine Art brings focused curatorial intelligence to the Western American art tradition, representing painters and sculptors who carry the grand narrative of the American West forward with technical mastery and genuine feeling for the subject. The gallery occupies a choice Old Town Scottsdale location and presents work ranging from monumental bronze sculpture — riders, horses, wildlife rendered in exacting naturalistic detail — to intimate plein air paintings made on location across the Southwest's most spectacular landscapes. Collectors who care about provenance, technical accomplishment, and the ongoing vitality of the Western tradition will find Tanner's program consistently worthwhile throughout the year.</p>` },
  { id: 4, full_description: `<p>Legacy Gallery has become one of the most trusted sources for American Western and wildlife art in Scottsdale, representing artists whose work is collected by serious buyers throughout the United States and internationally. The program is deliberately focused — Western landscapes, wildlife in their native habitat, the culture of the working ranch and rodeo, the Indigenous peoples of the Southwest — and pursues that focus with curatorial discipline, showing only artists whose technical command and interpretive vision meet a high standard. Bronze sculpture is a particular strength, with a stable of artists producing works that reward close attention and hold their value over time. An excellent stop for collectors building a serious Western art collection.</p>` },
  { id: 5, full_description: `<p>Lisa Sette Gallery has maintained its position as one of the most intellectually serious and curatorially ambitious galleries in the American Southwest since its founding in 1990, representing artists of national and international significance whose practices engage with the conceptual and formal questions that define contemporary art at its most rigorous. The gallery has introduced major figures to Scottsdale and Phoenix audiences who might not otherwise have encountered their work, and several artists from the roster have gone on to major museum acquisition and exhibition. Exhibitions are thoughtfully designed and accompanied by scholarly materials. Serious collectors make a point of visiting whenever they are in the Valley.</p>` },
  { id: 8, full_description: `<p>Medicine Man Gallery has been a leading source for both historical and contemporary Native American art since its founding in 1990, building expertise across the full breadth of Southwestern Indigenous artistic traditions — from ancient pottery and pre-contact textiles to the work of living master artists painting in the contemporary tradition. The gallery's historical holdings include rare antique pieces — Navajo blankets, Pueblo pottery, Hopi kachina figures — that appeal to museum-caliber collectors, while the contemporary program represents artists from Navajo, Hopi, Zuni, and other Southwestern nations. Expert staff are genuinely knowledgeable about provenance, tribal attribution, and market conditions — an important asset when navigating this specialized field.</p>` },
  { id: 15, full_description: `<p>Scottsdale Arts is the umbrella organization that shapes the cultural landscape of one of the Southwest's most arts-engaged cities, overseeing the Scottsdale Museum of Contemporary Art, a major public art collection with works throughout the city, the performing arts programs at Scottsdale Center for the Performing Arts, and an extensive calendar of community events and festivals. The organization's gallery programming introduces both established and emerging artists to Scottsdale's large and sophisticated arts audience, while its public art commissions make art a part of everyday life across the city. The Thursday evening gallery walk, coordinated with dozens of Old Town galleries, is one of the most vibrant regular art events in Arizona.</p>` },
  { id: 9, full_description: `<p>SMoCA — the Scottsdale Museum of Contemporary Art — has anchored the city's engagement with contemporary art, architecture, and design since opening in 1999 in a striking building designed by Will Bruder that incorporates the bones of an earlier cinema into a structure of considerable spatial drama. The exhibition program is ambitious and wide-ranging, presenting solo and group shows of contemporary significance alongside thoughtful explorations of architecture and design. The James Turrell Skyspace installed on the building's rooftop — one of the artist's signature contemplative environments — has become one of the most visited art experiences in Arizona. Admission is free on Thursday evenings, making SMoCA accessible to a broad Phoenix-area audience.</p>` },
  { id: 3, full_description: `<p>Trailside Galleries has been a defining presence on Scottsdale's Fifth Avenue since 1971, building a reputation over more than five decades as one of the premier destinations for traditional Western and wildlife art in the American Southwest. The gallery represents artists who work in the realist tradition — painters whose canvases document the American West with the care and attention of naturalists, and sculptors whose bronzes capture movement and texture in the manner of the great 19th-century masters — while maintaining standards of technical accomplishment that have made Trailside works consistently strong performers at auction. A focused, serious gallery for collectors who care deeply about craft and tradition.</p>` },
  { id: 137, full_description: `<p>Western Spirit: Scottsdale's Museum of the West opened in 2015 in a dramatic purpose-built facility in Old Town Scottsdale, offering 15,000 square feet of gallery space dedicated to exploring the art and history of the American West from the 19th century through the present day. Permanent galleries present paintings, sculpture, works on paper, and artifacts that trace the visual story of westward expansion, the natural landscape, and the diverse peoples — Indigenous, Hispanic, and Anglo-American — who shaped the region. Temporary exhibitions bring fresh perspectives and nationally significant artists throughout the year. Particularly strong on the period between 1865 and 1940, when the mythology and reality of the American West were first being negotiated in paint and bronze.</p>` },
  { id: 2, full_description: `<p>Wilde Meyer Gallery has been one of the most beloved and energetically programmed galleries in Scottsdale since its founding in 1992, building a devoted following for its commitment to vibrant, colorful contemporary Southwestern art that feels genuinely alive to the light and landscape of the desert Southwest. The gallery represents a multigenerational roster of established and emerging artists working in painting, printmaking, and mixed media, with a consistent curatorial bias toward work that hits hard visually and rewards sustained looking. Wilde Meyer is known for a genuinely welcoming atmosphere — the kind of gallery where new collectors feel encouraged rather than intimidated — and for prices that span an unusually wide range.</p>` },
  { id: 7, full_description: `<p>Founded in 2001, Xanadu Gallery has built a following as one of Old Town Scottsdale's most accessible and collector-friendly contemporary art galleries, representing more than 60 emerging and mid-career artists whose work is priced to be attainable for buyers at all levels of experience. The program spans painting, sculpture, and works on paper in a range of contemporary styles, with an emphasis on work that is visually engaging and technically accomplished without being intimidating to buyers still developing their eye. Xanadu is known for its educational approach — the gallery regularly hosts collector workshops and informal conversations about buying and caring for original art, making it an excellent starting point for new collectors in the Valley.</p>` },
  { id: 16, full_description: `<p>Established in 1982, the Sedona location of Exposures International Gallery was the original outpost of what became one of the Southwest's most celebrated gallery operations — and it remains a premier destination in its own right, set against the extraordinary backdrop of Sedona's red rock buttes and canyon walls. The program presents world-class painting, sculpture, and photography by artists of national and international reputation, in a space whose physical grandeur matches the ambition of the work on display. Sedona's extraordinary landscape has been an inexhaustible source of inspiration for American artists for over a century, and Exposures consistently represents artists who engage with it seriously — capturing not just its visual drama but its deeper geological and spiritual dimensions.</p>` },
  { id: 24, full_description: `<p>Gallery 527 brings an eclectic and refreshingly unpredictable curatorial sensibility to Uptown Sedona's gallery scene, with a rotating program that resists the region's gravitational pull toward predictable landscape painting in favor of a more adventurous mix. Exhibitions feature emerging Southwestern artists working in painting, ceramics, mixed media, and works on paper, often placing artists in conversation with one another across generations and media. The gallery's intimate scale makes it a place where work can be examined closely and conversations with staff unfold naturally. A good choice for visitors who want to see what young and mid-career artists are making in response to the Southwest's cultural and landscape richness.</p>` },
  { id: 23, full_description: `<p>Goldenstein Gallery occupies a setting of genuine natural drama — perched above Oak Creek Canyon in one of the most visually spectacular corridors in the American Southwest — and the work it presents rises to meet that setting. Dramatic landscape paintings, both plein air and studio-finished, are a particular strength: artists who have spent serious time in the canyons and mesas of northern Arizona produce work that captures the geological immensity and atmospheric power of the landscape beyond postcard beauty. Sculpture in bronze and stone complements the paintings, and the gallery's windows allow the actual canyon walls and creek to serve as a living backdrop to the work inside. An unusually immersive gallery experience.</p>` },
  { id: 17, full_description: `<p>Lanning Gallery occupies one of the most evocative settings in the Sedona gallery world — a space within the beloved Tlaquepaque Arts &amp; Shopping Village, a hand-built complex of courtyards, fountains, and Spanish colonial architecture that has been a gathering place for Sedona's art community since 1971. The gallery presents contemporary paintings and sculpture by artists whose work responds to the Southwest landscape with formal confidence and genuine feeling — neither tourist-trade decorative art nor inaccessible conceptualism, but work made with skill and rooted in genuine observation of the natural world. The Tlaquepaque setting adds considerable atmosphere, and the gallery is particularly worth visiting during one of the village's seasonal art festivals.</p>` },
  { id: 18, full_description: `<p>Mountain Trails Gallery is one of the anchors of the Tlaquepaque Arts Village gallery scene, presenting representational art of the American West — oil paintings, bronze sculpture, and hand-built ceramics — by artists who draw their subjects from the landscapes, wildlife, and cultural life of the Southwest. The gallery's program leans traditional in the best sense: technically accomplished work made by artists who have spent years studying their subjects in person, painting on location and casting from life studies to produce pieces that hold up to sustained viewing. Sedona's iconic sandstone formations and surrounding canyon country appear frequently alongside wildlife, Native American subjects, and the living landscape of the high desert Southwest.</p>` },
  { id: 21, full_description: `<p>Parks Gallery has built a devoted collector following in Sedona with a focused program dedicated to plein air and landscape painting — work made by artists who go into the canyons, mesas, and high desert meadows of northern Arizona and paint what they find there, in real light, in real time. This commitment to direct observation gives the work a freshness and atmospheric truth that studio painting rarely achieves, and the best pieces in the inventory capture specific qualities of Arizona light — the gold of late afternoon on red sandstone, the blue-violet shadow of canyon walls at dusk — that only a painter standing in that place could register. Located within Tlaquepaque Arts Village.</p>` },
  { id: 22, full_description: `<p>Renee Taylor Gallery occupies Uptown Sedona with a program dedicated to contemporary abstract and semi-abstract painting that takes its emotional cues from the extraordinary chromatic environment of red rock country — the burnt sienna of the cliffs, the turquoise of the high desert sky, the sage green of the scrub and juniper — without being literally representational of any of it. Artists in the program work with paint as a material that can carry sensation and feeling in its own right, and the result is a gallery experience that feels genuinely modern while remaining deeply connected to the landscape that makes Sedona one of the most color-saturated places in the country. An excellent counterpoint to the many landscape galleries on the same street.</p>` },
  { id: 19, full_description: `<p>Tlaquepaque Arts &amp; Shopping Village is one of the most beloved and architecturally distinctive art destinations in the American Southwest — a hand-built complex modeled after a traditional Mexican village, with terracotta-tiled courtyards, fountains, mature sycamore trees, and hand-painted tilework that creates an atmosphere of genuine warmth and beauty. More than 40 galleries, studios, and artisan shops occupy the village's interconnected spaces, presenting everything from fine art painting and bronze sculpture to handmade jewelry, ceramics, and blown glass. Founded in 1971 by Abe Miller, who wanted to create a space where art and commerce could coexist gracefully, Tlaquepaque remains one of the highlights of any visit to Sedona.</p>` },
  { id: 20, full_description: `<p>Turquoise Tortoise Gallery is a Sedona institution, curating an exceptional collection of authentic Native American jewelry, pottery, and fine art sourced directly from tribal artists across the Southwest. In a region where reproductions and inauthentic goods are unfortunately common, Turquoise Tortoise has built its reputation on a rigorous commitment to genuine Native-made work — pieces produced by Navajo, Hopi, Zuni, Pueblo, and Apache artists who are known by name and whose tribal affiliations are documented. The jewelry program is particularly strong: sterling silver and turquoise work in both traditional and contemporary styles, alongside coral, jet, spiny oyster, and the other materials that have defined Southwestern Native jewelry for generations.</p>` },
  { id: 182, full_description: `<p>The Arizona State University Art Museum has maintained one of the most distinguished collections of any university art museum in the American West since its founding in 1950, with holdings of over 5,000 works spanning American art from the colonial period to the present, a significant craft collection including studio ceramics and fiber art, Latin American art of genuine depth and quality, and a growing contemporary component that reflects ASU's active engagement with artists and ideas at the leading edge of the field. The museum's central Tempe campus location makes it easily accessible and admission is typically free, making it one of the best value cultural destinations in the Phoenix metro area.</p>` },
  { id: 184, full_description: `<p>Eye Lounge Tempe brings the artist-run cooperative model — and the experimental curatorial spirit that defines it — to the Tempe arts district, presenting boundary-pushing contemporary work by emerging Arizona-based artists in a space where the priority is clearly the work and the community around it rather than commercial metrics. Exhibitions rotate regularly and span painting, installation, performance documentation, video art, and new media, with a consistent openness to work that doesn't fit neatly into existing categories. The Tempe location serves the ASU creative community while maintaining independence from institutional constraints, creating a space where artists can take genuine risks and build relationships with an audience that responds to challenge and surprise.</p>` },
  { id: 183, full_description: `<p>The Tempe Center for the Arts opened in 2007 as one of the most architecturally striking public arts facilities built in Arizona in the 21st century — a LEED Silver-certified building designed by Architekton that appears to float above the surface of Tempe Town Lake, its angular form reflected in the water below. The visual arts program presents rotating gallery exhibitions in thoughtfully designed spaces with sweeping views of the lake and the Papago Buttes beyond, featuring regional and national contemporary artists whose work engages with the kinds of environmental and cultural themes that resonate in a desert city built on a reclaimed riverbed. The performing arts program creates a lively evening atmosphere that extends well beyond gallery hours.</p>` },
  { id: 122, full_description: `<p>Founded in 1893 — making it the oldest and largest anthropology museum in the Southwest — the Arizona State Museum at the University of Arizona holds collections of extraordinary depth and significance, anchored by a world-renowned assemblage of more than 40,000 Native American pottery vessels from across the Southwest. The collection documents centuries of ceramic tradition from dozens of Pueblo, O'odham, Apache, and other Indigenous cultures, providing an unmatched resource for scholars, artists, and visitors seeking to understand the material and artistic heritage of the region. The museum also maintains major collections of basketry, weaving, and archaeological material from throughout the Southwest and northern Mexico, and hosts rotating exhibitions that bring fresh perspectives to this deep historical record.</p>` },
  { id: 26, full_description: `<p>Since its founding in 1997, Davis Dominguez Gallery has established itself as Tucson's leading venue for ambitious contemporary art, consistently presenting painting, sculpture, and new media work by established and emerging artists of regional and national significance. The gallery's exhibition program moves fluidly between solo presentations of depth and group shows that reveal unexpected connections between artists, and it maintains a long-term commitment to artists whose careers it has supported over many years. Located in downtown Tucson, Davis Dominguez is a natural anchor of the city's monthly First Saturday Art Walk, and its opening receptions draw the full breadth of Tucson's engaged arts community. Essential visiting for any serious student of contemporary Southwest art.</p>` },
  { id: 30, full_description: `<p>Dinnerware Artspace has been Tucson's most committed incubator of experimental and community-engaged contemporary art since its founding in 1979 — a span of more than four decades that makes it one of the longest-running artist-run spaces in the American Southwest. The ethos of Dinnerware has remained consistent across that history: art made in genuine relationship to community, shown in an informal atmosphere that prioritizes access and conversation over the conventions of commercial gallery culture. Exhibitions rotate regularly and have featured work in virtually every medium, with particular openness to performance, installation, and new media. A beloved institution in Tucson's creative community and a must-visit for anyone serious about understanding the city's art scene.</p>` },
  { id: 32, full_description: `<p>The Drawing Studio occupies a distinctive niche in Tucson's arts ecosystem as a community center built around the foundational practices of visual art — drawing, painting, printmaking, and the study of the human figure — in a city with a strong tradition of figurative and observational art rooted in its proximity to the Sonoran Desert landscape and the US-Mexico borderlands. Classes and workshops serve students from beginners to working professional artists, with a consistent emphasis on close observation and the development of genuine technical skill. The gallery presents rotating exhibitions of student and invited artist work, creating a public face for a community of makers who value craft and direct engagement with the visible world.</p>` },
  { id: 25, full_description: `<p>Etherton Gallery has been the premier destination for fine art photography in the American Southwest since its founding in 1981, building a program that spans 19th-century documentary photography — frontier surveys, ethnographic portraits, early landscape work from the era before the railroads — to contemporary fine art photographers working in traditions that connect directly to that history. The gallery has introduced important bodies of work to Arizona audiences and built significant collections for institutions and private buyers who recognized the historical and aesthetic importance of what it was showing. Etherton is known for scholarly depth: the staff can discuss provenance, process, and photographic history with genuine authority, making it as useful as a resource as it is as a gallery.</p>` },
  { id: 123, full_description: `<p>The Ignite Sign Art Museum is one of the most delightfully singular cultural institutions in Tucson — a museum dedicated to preserving and celebrating the neon and vintage sign heritage of a city and a region where commercial signage has long been an art form in its own right. The collection spans restored neon signs from mid-century Tucson businesses, hand-painted trade signs, porcelain enamel advertising pieces, and painted billboards that document the visual culture of the 20th-century Southwest with vivid specificity. Seeing these objects out of their original context — lit and legible in a museum setting — reveals the craftsmanship, graphic sophistication, and cultural specificity that made them worth preserving. A genuinely joyful museum experience.</p>` },
  { id: 29, full_description: `<p>Philabaum Contemporary Art Glass has been the leading destination for studio art glass in the Tucson area since 1980, maintaining an exclusive focus on handblown and kiln-formed glass by leading artists from across the United States in a program that has educated the Tucson market about what the medium can achieve at the highest level. Studio art glass emerged from the American craft movement of the 1960s and has since produced artists of major international significance — and Philabaum has consistently sought out the best of them, representing artists whose work is collected by major museums and serious private collectors. Visitors unfamiliar with the medium are often astonished by what handblown glass is capable of in the hands of a true master.</p>` },
  { id: 31, full_description: `<p>Settlers West Galleries has established itself as one of the most respected sources for classic and contemporary Western and wildlife art in Southern Arizona, operating from a Tucson Foothills location that reflects the gallery's alignment with the outdoor, landscape-oriented culture of the city's north side. The program spans the Western American fine art tradition in depth — oils, watercolors, and pastels depicting the desert Southwest, the Rocky Mountain West, and the wildlife that inhabits those landscapes — with particular attention to artists whose work has stood the test of time and whose technical accomplishment warrants serious collector attention. The gallery's annual Western Art Show, typically held in the fall, is one of the most anticipated events on the Tucson arts calendar.</p>` },
  { id: 124, full_description: `<p>The Tucson Clay Co-op functions as Tucson's primary community home for the ceramic arts — a working studio where members have access to wheels, kilns, hand-building tables, and the shared knowledge of a community of potters that spans beginners learning to center clay for the first time to professional artists with established exhibition careers. The co-op's gallery presents rotating exhibitions of member work and occasional invited artists, creating a public window into the breadth and depth of ceramic practice happening within the studio. Classes and workshops introduce students of all ages and experience levels to the medium, and the open studio model encourages the kind of informal learning and exchange between artists that formal art education often can't replicate.</p>` },
  { id: 27, full_description: `<p>Founded in 1924, the Tucson Museum of Art is the oldest and most comprehensive art museum in southern Arizona, with permanent collections spanning pre-Columbian art and artifacts, Spanish Colonial furniture and devotional painting, American Western art, modern painting and sculpture, and contemporary work by regional and national artists. The museum's historic campus in downtown Tucson encompasses several 19th-century adobe structures alongside the main museum building — a spatial arrangement that gives it an architectural richness and sense of historical rootedness unique among Arizona museums. The Folk Art of the Americas collection is particularly distinguished, and the museum's changing temporary exhibitions regularly bring significant work from national and international lenders to Tucson audiences.</p>` },
  { id: 28, full_description: `<p>The University of Arizona Museum of Art holds one of the most distinguished permanent collections of any university art museum in the Southwest, with particular strengths in European paintings and sculpture from the Renaissance through the 20th century, American art from the colonial period to the present, and works on paper — prints, drawings, and photographs — spanning six centuries of Western art history. The Kress Collection of Renaissance and Baroque paintings, donated to the museum in 1960, includes works by Tintoretto, Veronese, and other major masters of the period. Located on the University of Arizona campus and typically free for students and low-cost for the public, it is one of Tucson's most accessible and underappreciated cultural treasures.</p>` },
];

async function run() {
  let success = 0;
  for (const { id, full_description } of updates) {
    await sql`UPDATE listings SET full_description = ${full_description} WHERE id = ${id}`;
    success++;
    if (success % 10 === 0) console.log(`Updated ${success}/${updates.length}...`);
  }
  console.log(`Done. Updated ${success} listings.`);
}

run().catch(console.error);
